// STEP 2 — Extract message text and chat ID from Telegram's payload
// Telegram sends updates in this shape:
// { update_id: 123, message: { text: '...', chat: { id: 456 }, from: { username: 'tj' } } }

const update   = $input.item.json.body;
const message  = update.message || update.edited_message;

if (!message || !message.text) {
  // Not a text message (could be photo, sticker, etc.) — skip
  return [];
}

return [{
  json: {
    text:     message.text.trim(),
    chat_id:  String(message.chat.id),
    username: message.from?.username || message.from?.first_name || `tg_${message.chat.id}`,
    // Determine workflow from message keywords
    workflow: message.text.toLowerCase().includes('weather') ? 'weather_report'
            : message.text.toLowerCase().includes('ticket') ? 'jira_triage'
            : 'general',
  }
}];
